// apps/web/vendor-dashboard/quiz-engine/questionBanks.js
// Auto-extracted from TradeMatch-Vetting-Quiz-Preview.html — DO NOT EDIT MANUALLY

'use strict';

const BANKS = {
gas:{name:'Gas Engineer',emoji:'🔥',questions:[
{id:'g1',type:'scenario',level:1,competency:'regulation',text:'A new tenant moves into a property. When must the landlord\'s gas safety record (CP12) be provided?',options:['Within 12 months of tenancy start','Before the tenancy begins, or within 28 days of a new check','Within 3 months of tenancy start','Annually from property purchase date'],correct:1,explanation:'Under the Gas Safety (Installation and Use) Regulations 1998, landlords must provide tenants a copy of the current gas safety record before the tenancy begins, or within 28 days of a new check being completed mid-tenancy.'},
{id:'g2',type:'safety',level:1,competency:'safety',text:'You arrive at a property and smell gas strongly. The client says the smell has been present for several hours. What is your FIRST action?',options:['Identify the source with a gas analyser','Evacuate the property and call the National Gas Emergency line — 0800 111 999','Open all windows before investigating','Apply leak detection fluid to visible pipework'],correct:1,explanation:'Life safety first. With a prolonged gas leak evacuate immediately and call the emergency line. Never operate electrical switches or use flames inside the building before evacuating.'},
{id:'g3',type:'technical',level:2,competency:'technical',text:'You commission a new combi boiler. System pressure drops from 1.5 bar to 0.8 bar within 24 hours with no visible external leaks. Most likely cause?',options:['Failed expansion vessel pre-charge','Air trapped in radiators','System overfilled at commissioning','Undersized pressure relief valve'],correct:0,explanation:'A rapid pressure drop with no visible leaks is a classic sign of an under-pressurised or failed expansion vessel. The vessel pre-charge should match the system static fill pressure (typically 0.5–0.75 bar for a two-storey property).'},
{id:'g4',type:'scenario',level:2,competency:'judgement',text:'A landlord asks you to "just pass" their CP12 as the boiler is being replaced next month. You observe signs of heat exchanger cracking. What do you do?',options:['Issue a warning notice and mark as At Risk (AR)','Issue the CP12 — the landlord accepts responsibility','Issue an Immediately Dangerous (ID) notice and advise the landlord in writing','Refuse the job and leave without documentation'],correct:2,explanation:'A cracked heat exchanger is an Immediately Dangerous situation (CO risk). Issue an ID notice, disconnect with permission, and advise in writing. Issuing a false CP12 is a criminal offence and risks loss of Gas Safe registration.'},
{id:'g5',type:'regulation',level:1,competency:'regulation',text:'Which regulation requires that only Gas Safe registered engineers carry out gas work?',options:['Health and Safety at Work Act 1974','Gas Safety (Installation and Use) Regulations 1998','Building Regulations Part J','Gas Act 1986'],correct:1,explanation:'The Gas Safety (Installation and Use) Regulations 1998 make it a criminal offence for anyone not Gas Safe registered to work on gas fittings in domestic or commercial premises.'},
{id:'g6',type:'technical',level:2,competency:'technical',scenario:'You are replacing a gas hob. The supply pipe is 15mm copper running 4 metres from the meter. The new hob has a rated input of 14kW.',text:'Is the existing 15mm supply adequate?',options:['Yes — 15mm handles up to 20kW over 4 metres','No — 14kW over 4 metres requires 22mm minimum','Yes — hobs are low-pressure, 15mm is always sufficient','No — all hob connections must be 22mm regardless of distance'],correct:1,explanation:'Using BS 6891 pipe sizing tables, a 14kW appliance over 4 metres requires 22mm pipe to maintain adequate pressure drop. 15mm is adequate only for lower loads or shorter runs.'},
{id:'g7',type:'truefalse',level:1,competency:'safety',text:'TRUE or FALSE: A carbon monoxide detector replaces the need to carry out combustion analysis on a gas appliance.',correct:false,explanation:'FALSE. CO detectors are life-safety alarms, not substitutes for combustion analysis. Analysis verifies efficiency, identifies incomplete combustion, and is required best practice under GSIUR 1998.'},
{id:'g8',type:'select-all',level:2,competency:'technical',text:'When completing a tightness test on a domestic gas installation, which are correct? Select ALL that apply.',options:['Apply 20 mbar test pressure','Allow a 1-minute stabilisation period','A pressure drop of 0 mbar indicates a sound installation','Carry out the test with all appliances isolated','Acceptable pressure drop is ≤4 mbar over 2 minutes'],correct:[0,2,3,4],explanation:'The domestic tightness test uses 20 mbar, appliances isolated, 1-min stabilisation, then 2-minute test. Zero drop is ideal; ≤4 mbar is acceptable.'},
{id:'g9',type:'scenario',level:3,competency:'judgement',scenario:'A tenant calls you to service their boiler. You discover the gas meter is in a locked cupboard under the stairs with no ventilation grille as required by regulations.',text:'What is the correct course of action?',options:['Service the boiler and advise the tenant to speak to the landlord','Refuse to work until the landlord corrects the ventilation','Serve an At Risk (AR) notice on the meter location and advise the landlord in writing to rectify','Report directly to HSE immediately'],correct:2,explanation:'A meter enclosure lacking required ventilation is an At Risk situation. Issue AR documentation, advise the landlord in writing. You can still service the boiler as the meter deficiency alone does not make the boiler immediately dangerous.'},
{id:'g10',type:'technical',level:3,competency:'technical',text:'Installing a new 25kW combi where a 12kW existed. The 22mm supply runs 8 metres from the meter. What must you verify before completing the installation?',options:['That the flue is Type C','Pipe adequacy using sizing tables — the increased demand may require upgrade to 28mm','That the boiler is A-rated','That the meter has been upgraded to a U6'],correct:1,explanation:'Doubling the appliance rating requires re-checking the full installation pipe sizing under BS 6891. At 25kW over 8 metres, 22mm may be marginal depending on total gas load. You may need to upgrade to 28mm or advise the gas transporter to assess the meter.'},
{id:'g11',type:'truefalse',level:2,competency:'regulation',text:'TRUE or FALSE: You are legally required to leave a completed Visual Inspection Report (VIR) with the homeowner after every domestic gas appliance service.',correct:false,explanation:'FALSE. A VIR is good practice but not a legal requirement for domestic properties. The legal requirement (CP12) applies to landlord safety checks only.'},
{id:'g12',type:'scenario',level:3,competency:'judgement',scenario:'During a boiler service, combustion analysis shows a CO/CO₂ ratio of 0.008. The maximum acceptable for a Type C appliance is 0.004.',text:'What action is required?',options:['Accept it — variance is expected on a 4-year-old boiler','Service and clean the burner and heat exchanger, retest — if still above threshold, condemn the appliance','Issue a warning notice; advise homeowner of potential replacement within 5 years','CO/CO₂ ratio is irrelevant — only CO ppm in flue matters'],correct:1,explanation:'A CO/CO₂ ratio above 0.004 indicates incomplete combustion. Clean the heat exchanger, check burner and air supply, retest. If still above threshold, the appliance must be condemned as Immediately Dangerous.'},
{id:'g13',type:'calculation',level:2,competency:'technical',text:'A gas installation has a measured gas rate of 2.2 m³/hr. Using a calorific value of 38.76 MJ/m³ and a conversion factor of 3.6 (MJ to kW), what is the approximate heat input?',unit:'kW',correct:23.7,tolerance:1.5,explanation:'Heat input (kW) = (m³/hr × CV) ÷ 3.6 = (2.2 × 38.76) ÷ 3.6 = 85.272 ÷ 3.6 = 23.7 kW. Gas rate calculations verify the appliance is operating at its rated input.'}
]},
electrical:{name:'Electrician',emoji:'⚡',questions:[
{id:'e1',type:'scenario',level:1,competency:'regulation',text:'A client asks you to replace their consumer unit. Under which regulation is this notifiable work in England and Wales?',options:['IET Wiring Regulations (BS 7671)','Part P of the Building Regulations','Electrical Equipment Safety Regulations 2016','Health and Safety at Work Act 1974'],correct:1,explanation:'Consumer unit replacement is notifiable under Part P of the Building Regulations. It must be self-certified through a Competent Person Scheme (NICEIC, NAPIT) or notified to Building Control before the work starts.'},
{id:'e2',type:'technical',level:1,competency:'technical',text:'2.5mm² T&E cable clipped direct (reference method C, BS 7671 Appendix 4) has a current-carrying capacity of:',options:['18A','27A','32A','20A'],correct:1,explanation:'2.5mm² two-core T&E clipped direct (method C) has a rating of 27A. In thermal insulation (method A) this falls to 13A. A 20A MCB may protect the circuit but the conductor rating must still exceed the device rating after derating.'},
{id:'e3',type:'scenario',level:2,competency:'safety',scenario:'Installing an EV charger in a detached garage. The property has a PME (TN-C-S) earthing system. The garage is a separate outbuilding with an underground supply.',text:'What additional safety requirement applies before installing the EV charger?',options:['None — PME earthing is always safe','Install a Type 2 SPD only','Provide an earth electrode and 30mA RCD at the outbuilding, or use a TT earthing arrangement','Upgrade the consumer unit to a dual-RCD board'],correct:2,explanation:'BS 7671 Reg 722.411.4.1: for EV charging on PME systems, either a TT earthing system with RCD is used, or a risk assessment confirms PME is safe. For outbuildings, the standard solution is an earth electrode plus 30mA RCD due to lifted-neutral fault risk.'},
{id:'e4',type:'select-all',level:2,competency:'technical',text:'Which tests MUST be performed on a new circuit before energisation? Select ALL that apply.',options:['Insulation resistance test','Earth fault loop impedance test','Continuity of protective conductors','Polarity test','RCD operating time test'],correct:[0,2,3],explanation:'Pre-energisation tests (BS 7671 Part 6): continuity of protective conductors, ring circuit continuity (where applicable), insulation resistance, and polarity. Earth fault loop impedance and RCD tests are post-energisation.'},
{id:'e5',type:'regulation',level:1,competency:'regulation',text:'An EICR reveals code C2. What does this mean for a landlord under the Electrical Safety Standards Regulations 2020?',options:['Safe — no further action','Potentially dangerous — remedial work within 28 days','Immediately dangerous — isolate before re-occupation','Improvement recommended — no timeframe'],correct:1,explanation:'C2 (Potentially Dangerous) requires remedial work within 28 days. C1 (Immediately Dangerous) requires action before re-occupation. The landlord must provide evidence of remediation to both the tenant and local authority.'},
{id:'e6',type:'scenario',level:3,competency:'judgement',scenario:'Rewiring a 1965 property with TN-C-S (PME) earthing. Ze = 0.38Ω. New circuits include outdoor sockets and garden lighting.',text:'What should you recommend for the outdoor circuits?',options:['Standard PME earthing is adequate for all outdoor use','30mA RCD required — additional earth electrode beneficial for garden circuits on PME','All outdoor circuits must use a separate TT system','PME outdoor circuits require armoured cable only'],correct:1,explanation:'BS 7671 requires 30mA RCD for all outdoor circuits regardless of earthing system. On PME, a lifted neutral can cause dangerous voltage on exposed metalwork. An earth electrode for garden circuits is best practice. The Ze confirms PME but does not remove the outdoor RCD requirement.'},
{id:'e7',type:'truefalse',level:1,competency:'safety',text:'TRUE or FALSE: A 30mA RCD provides complete protection against all electric shock risks in all circumstances.',correct:false,explanation:'FALSE. A 30mA RCD provides additional protection but not a guarantee in all circumstances. It will not operate on a line-to-line fault not flowing through the RCD, and specific cardiac risks can exist at currents below 30mA under certain conditions.'},
{id:'e8',type:'calculation',level:2,competency:'technical',text:'A 32A ring final uses 2.5mm² T&E cable with total ring length 50 metres. Resistance of 2.5mm² copper = 7.41 mΩ/m. What is the measured end-to-end resistance of one conductor along the full ring?',unit:'mΩ',correct:185,tolerance:20,explanation:'Ring circuit conductor resistance = 7.41 × 50 / 2 = 185.25 mΩ ≈ 185 mΩ. R1+R2 at mid-ring (hardest to protect point) = half this value ≈ 92.6 mΩ.'},
{id:'e9',type:'scenario',level:2,competency:'judgement',scenario:'A property has a TT system with a 100mA whole-board RCD. A new garden socket circuit is to be added.',text:'Can the garden socket connect to the existing board without additional RCD protection?',options:['Yes — TT with 100mA RCD meets garden socket requirements','No — garden sockets require a dedicated 30mA RCD regardless of board configuration','Yes — TT provides better shock protection than PME','No — garden circuits must always have a separate earth electrode'],correct:1,explanation:'BS 7671 Reg 411.3.3 requires additional protection (30mA RCD) for ALL socket outlets used outdoors. The 100mA whole-board RCD provides fault protection only — not the additional protection against direct contact required by Regulation 415.'},
{id:'e10',type:'technical',level:3,competency:'technical',text:'For a TT system circuit protected by a 30mA RCD, BS 7671 Table 41.1 requires disconnection within how many seconds (circuits up to 32A at 230V)?',options:['0.2 seconds','0.4 seconds','5 seconds','1 second'],correct:0,explanation:'TT systems require disconnection within 0.2 seconds for circuits up to 32A at 230V. TN systems get 0.4 seconds. The shorter time reflects the higher fault impedance possible on TT systems and correspondingly higher touch voltages.'},
{id:'e11',type:'regulation',level:2,competency:'regulation',text:'Under BS 7671 Appendix 12, the maximum permitted voltage drop for a lighting circuit from the origin of installation to the load is:',options:['1%','3%','5%','8%'],correct:1,explanation:'BS 7671 Appendix 12 permits maximum 3% for lighting and 5% for power circuits, from the origin to the load under normal service conditions, based on a nominal 230V supply.'},
{id:'e12',type:'scenario',level:3,competency:'judgement',scenario:'Testing a circuit serving a 20-year-old immersion heater. Insulation resistance = 0.45 MΩ. Minimum required: 1 MΩ.',text:'What is the most appropriate action?',options:['Issue C3 — some resistance remains','Issue C2 and investigate — the immersion element may be breaking down','Simply replace the cable and retest','The circuit passes — 0.45 MΩ exceeds the 0.1 MΩ absolute minimum'],correct:1,explanation:'Minimum required IR for a 230V circuit is 1 MΩ (BS 7671). 0.45 MΩ is a fail — C2 at minimum. For a 20-year-old immersion heater, likely cause is a deteriorating element with partial earth fault. Investigate the cause before specifying remedial works.'},
{id:'e13',type:'truefalse',level:1,competency:'regulation',text:'TRUE or FALSE: A registered electrician can self-certify a like-for-like socket replacement in a living room without notifying Building Control.',correct:true,explanation:'TRUE. Schedule 4 Part P exemptions permit minor work (adding a socket to an existing circuit, or like-for-like replacement) in non-special locations without notification — as long as no new circuit is created. Kitchens and bathrooms are special locations.'}
]},
plumbing:{name:'Plumber',emoji:'🚰',questions:[
{id:'p1',type:'scenario',level:1,competency:'regulation',text:'Before installing a new cold water storage cistern over 10 litres, what must you do under the Water Supply (Water Fittings) Regulations 1999?',options:['Notify Building Control','Notify the local water undertaker, unless you are an approved contractor','Submit a COSHH assessment','Nothing — cistern installation is unregulated'],correct:1,explanation:'The Water Supply (Water Fittings) Regulations 1999 require advance notification to the local water undertaker for prescribed categories of work (including cisterns over 10L) unless carried out by an approved contractor. The water company can inspect on completion.'},
{id:'p2',type:'technical',level:1,competency:'safety',text:'What is the minimum hot water storage temperature recommended by HSE ACOP L8 to prevent Legionella growth?',options:['45°C','55°C','60°C','50°C with a weekly 70°C pasteurisation cycle'],correct:2,explanation:'HSE ACOP L8 recommends stored hot water held at minimum 60°C. At 60°C Legionella is killed within 2 minutes. Cold water should be stored below 20°C.'},
{id:'p3',type:'scenario',level:2,competency:'judgement',scenario:'Fitting a shower tray with a 50mm low-profile trap. Outlet connects to a 40mm horizontal waste pipe running 3 metres to the soil stack.',text:'What is the potential problem and how would you address it?',options:['Trap depth is insufficient — use a 75mm deep seal trap','Excessive fall on the 40mm pipe may cause self-siphonage — check fall is 1:40 to 1:80','The 40mm pipe must be upgraded to 50mm','Low-profile traps are not approved for showers'],correct:1,explanation:'Long horizontal waste runs with excessive fall cause self-siphonage, emptying the trap seal. BS EN 12056 specifies a fall of 1:40 to 1:80 (18–35mm drop over 3m) for 40mm waste. A 75mm deep seal trap helps in borderline cases.'},
{id:'p4',type:'technical',level:2,competency:'technical',text:'What is a Type AA air gap in water supply?',options:['An overflow pipe with minimum 25mm bore','An unobstructed free space between the inlet lowest point and the critical water level','A non-return valve on the cold supply inlet','An overflow pipe connected to a separate drain'],correct:1,explanation:'A Type AA air gap is the highest level of backflow protection — a physical air gap between the inlet spill-over level and the critical water level. It physically prevents backflow regardless of pressure conditions.'},
{id:'p5',type:'regulation',level:1,competency:'regulation',text:'Under BS EN 806, hot water must be available at any draw-off point within 60 seconds at a minimum temperature of:',options:['45°C','50°C','55°C','No minimum specified'],correct:0,explanation:'BS EN 806 specifies hot water available at not less than 45°C at any outlet within 60 seconds for new installations. This does not override the Legionella storage requirement of 60°C.'},
{id:'p6',type:'scenario',level:2,competency:'safety',scenario:'A client asks you to connect a gas hob. You are not Gas Safe registered.',text:'What should you do?',options:['Connect it as a simple favour','Refuse — gas appliance connections require Gas Safe registration regardless of complexity','Connect it but advise the client to get it checked','Push-fit connections are exempt from Gas Safe requirements'],correct:1,explanation:'The Gas Safety (Installation and Use) Regulations 1998 require Gas Safe registration for any work on gas fittings — including connecting an appliance. No exceptions exist for "simple" connections.'},
{id:'p7',type:'select-all',level:2,competency:'technical',text:'When commissioning a new unvented hot water cylinder, which checks are REQUIRED? Select ALL that apply.',options:['Set and test the expansion vessel pre-charge pressure','Verify the temperature and pressure relief valve (TPRV) operates correctly','Test the thermostatic expansion valve at rated temperature','Check the tundish and discharge pipe route to safe discharge','Record working pressure and temperature in commissioning documentation'],correct:[0,1,3,4],explanation:'Commissioning an unvented cylinder requires: expansion vessel pre-charge check, TPRV verification, discharge route check (tundish visible, pipe run correct per G3), and completed commissioning documentation. The TEV is not manually tested at commissioning in this way.'},
{id:'p8',type:'scenario',level:3,competency:'judgement',scenario:'A 3-storey Victorian terrace reports poor hot water pressure at the top-floor bathroom. The property has a vented cylinder on the second floor.',text:'Most likely cause and most appropriate solution?',options:['Install a pump on the cold supply to the cylinder','Insufficient head from the cold water cistern — shower pump or conversion to unvented system','Raise the boiler flow temperature to 75°C','Replace 15mm hot pipework with 22mm'],correct:1,explanation:'In a vented system, pressure is governed by head from the cistern. With the cistern only one floor above the bathroom, head is typically 0.1–0.3 bar — too low for a satisfying shower. Solutions: shower pump, whole-house pump on hot/cold feeds, or conversion to unvented/combination system.'},
{id:'p9',type:'truefalse',level:2,competency:'regulation',text:'TRUE or FALSE: Under the Water Supply (Water Fittings) Regulations, a standard compression fitting may be used underground on a water supply pipe.',correct:false,explanation:'FALSE. Standard compression fittings (BS 864 olive type) must not be used underground. Underground water supply pipes must use push-fit fittings rated for underground use, solder capillary joints, or approved press-fit connections.'},
{id:'p10',type:'calculation',level:2,competency:'technical',text:'A drain run of 100mm diameter must fall at a gradient of 1:80. Over a run of 12 metres, what is the total fall required?',unit:'mm',correct:150,tolerance:5,explanation:'Fall = length ÷ gradient = 12000 ÷ 80 = 150 mm. A 100mm soil pipe at 1:80 achieves self-cleansing velocity without excessive fall that could strand solids.'},
{id:'p11',type:'scenario',level:3,competency:'judgement',text:'A client wants a soakaway for surface water and asks if the bathroom basin overflow can also drain to it. What is your advice?',options:['Yes — it is all clean water','No — foul waste must connect to the foul sewer, not a soakaway','Depends on local building control — no national rule','Yes — sink overflow is greywater and is permitted in soakaways'],correct:1,explanation:'Building Regulations Part H requires foul water to connect to the public sewer, cesspool, or septic tank — NOT a soakaway. A bathroom basin overflow is classified as foul drainage. Surface water soakaways must receive only clean, uncontaminated rainwater.'},
{id:'p12',type:'technical',level:3,competency:'technical',text:'Under BS EN 806-3, Loading Units (LU) for pipe sizing represent:',options:['A direct flow rate in litres per second','A probabilistic design tool — LU values are converted to flow rates via Table B.1, not used directly','Half the peak flow in litres per minute','Pipe diameter in millimetres required'],correct:1,explanation:'Loading units are a probabilistic design tool accounting for simultaneous use probability by building type. BS EN 806-3 Table B.1 converts total LU values to design flow rates. Simply treating LU values as litres per second significantly oversizes the system.'}
]},
roofing:{name:'Roofer',emoji:'🏠',questions:[
{id:'r1',type:'regulation',level:1,competency:'regulation',text:'Which British Standard is the code of practice for slating and tiling on pitched roofs?',options:['BS 5534','BS 8000','BS 5250','BS 6229'],correct:0,explanation:'BS 5534:2014+A2:2018 is the code of practice for slating and tiling for pitched roofs and vertical cladding. It covers fixing specifications, lap calculations, and exposure zone requirements.'},
{id:'r2',type:'scenario',level:2,competency:'safety',scenario:'Starting a 4-hour roof repair on a 2-storey semi. No scaffolding is in place.',text:'What is the minimum compliant safe working at heights provision?',options:['A roof ladder plus someone to hold the base ladder','A harness only attached to a ridge anchor','Edge protection (scaffolding or working platform) OR a personal fall arrest system — a roof ladder alone is insufficient above 2 metres','Edge protection only required for jobs lasting more than one full day'],correct:2,explanation:'Work at Height Regulations 2005: eliminate, then prevent, then minimise. A roof ladder provides access but not fall protection. For work above 2m, a roof ladder plus personal fall arrest (harness, lanyard, anchor) OR scaffolding/working platform with guard rails is required.'},
{id:'r3',type:'technical',level:1,competency:'technical',text:'The minimum recommended pitch for standard interlocking concrete tiles in a sheltered exposure zone is:',options:['12.5°','17.5°','22.5°','30°'],correct:1,explanation:'Most standard interlocking concrete tiles have a minimum pitch of 17.5° (sheltered exposure), rising to 22.5° in normal/severe zones. Always confirm with the specific tile manufacturer guidance alongside BS 5534.'},
{id:'r4',type:'scenario',level:2,competency:'judgement',scenario:'Inspecting an 8-year-old EPDM flat roof. A blister approximately 500×300mm is forming near a corner detail. The membrane otherwise appears sound.',text:'Most likely cause and recommended action?',options:['UV degradation — full replacement immediately','Full replacement is the only solution','Trapped moisture or air — carefully open, dry thoroughly, rebond, heat-weld a cover strip over the repair','Thermal movement — normal, no action needed'],correct:2,explanation:'Localised blistering on an otherwise sound 8-year-old EPDM is almost always trapped moisture or air. Open the blister, dry completely, apply contact adhesive, bond firmly, heat-weld a cover strip. Full replacement at 8 years is premature — EPDM has a 25+ year lifespan.'},
{id:'r5',type:'regulation',level:2,competency:'regulation',text:'Under CDM 2015, when does a domestic roofing project become notifiable to HSE?',options:['Any commercial roof project','Any project lasting more than 3 working weeks','Projects exceeding 30 working days with 20+ workers simultaneously, OR 500 person-days','All roof work over 2m height'],correct:2,explanation:'CDM 2015 Regulation 6 requires F10 notification to HSE when a project will last more than 30 working days with 20+ workers simultaneously, OR exceed 500 person-days. Most domestic re-roofs do not reach this threshold.'},
{id:'r6',type:'technical',level:2,competency:'technical',text:'What is the primary function of counter battens (vertical battens) in a modern pitched roof?',options:['Provide fixing points on curved rafters','Create a ventilation and drainage zone above the underlay, allowing water to drain freely','Add structural rigidity to shallow-pitch roofs','Counter battens are only used on green/living roofs'],correct:1,explanation:'Counter battens run parallel to rafters above the underlay, creating (1) an air/drainage plane for any water penetrating the tile covering and (2) ventilation to prevent interstitial condensation. Essential where breathable underlays are used.'},
{id:'r7',type:'truefalse',level:1,competency:'safety',text:'TRUE or FALSE: An extension ladder can be the sole means of access to a domestic roof for work lasting less than 30 minutes without additional fall protection.',correct:false,explanation:'FALSE. The Work at Height Regulations 2005 contain no time exemption. A ladder is an access device, not a working platform where significant fall risk exists. Roof work requires appropriate fall protection regardless of duration.'},
{id:'r8',type:'scenario',level:3,competency:'judgement',scenario:'Re-roofing a 1930s semi. On removing the tiles you discover the rafter level has been heavily insulated with closed-cell spray foam applied directly to the underside of the felt and rafters.',text:'Primary structural concern and recommended action?',options:['Spray foam adds rigidity — no concern','Spray foam may have caused moisture trapping and timber rot — a structural engineer must inspect before re-covering','Remove the spray foam immediately as it is a fire hazard under BS 5534','Remove the foam and replace with mineral wool before re-tiling'],correct:1,explanation:'Spray foam prevents ventilation, traps moisture causing timber rot, and makes re-mortgaging nearly impossible. Halt work, advise the client in writing, and recommend a structural timber survey before re-covering. Covering without inspection creates significant liability risk.'},
{id:'r9',type:'technical',level:3,competency:'technical',text:'Replacing a 6-metre lead valley gutter using Code 5 lead. Maximum single sheet length per LBIA guidance is:',options:['1.5m','1.8m','3.0m','6.0m in one sheet'],correct:1,explanation:'LBIA guidelines specify maximum sheet lengths of 1.5m for Code 5 lead in a valley (Code 6 allows up to 1.8m). Exceeding these lengths causes fatigue cracking from thermal movement. A 6m valley requires 4 Code 5 sheets with correct laps and expansion provisions.'},
{id:'r10',type:'calculation',level:2,competency:'technical',text:'A pitched roof has a 6m span at 35° pitch. What is the common rafter length from wall plate to ridge? (cos 35° ≈ 0.819)',unit:'metres',correct:3.66,tolerance:0.15,explanation:'Rafter length = half-span ÷ cos(pitch) = 3.0 ÷ 0.819 = 3.66 m. Add eaves overhang and deduct for ridge board width to get cutting length.'},
{id:'r11',type:'scenario',level:3,competency:'judgement',text:'A homeowner wants liquid waterproofing coating over existing cracked asphalt. The asphalt is 25+ years old with widespread crazing and two visible cracks. What do you recommend?',options:['Apply liquid coating over the entire surface — this is valid','Crack-fill and coat — will last another 10 years','Strip and replace the asphalt or install a new flat roof system — coatings over end-of-life asphalt are not durable','The client can apply a DIY coating'],correct:2,explanation:'Widespread crazing on 25-year-old asphalt indicates end-of-life oxidisation throughout the material. Coatings provide temporary waterproofing but may trap moisture. Recommend full replacement (GRP, EPDM, or IKO/Sika membrane). Document your advice in writing.'},
{id:'r12',type:'truefalse',level:2,competency:'regulation',text:'TRUE or FALSE: Breathable (vapour-permeable) roofing underlays eliminate the need for eaves-to-ridge ventilation in cold roof constructions.',correct:false,explanation:'FALSE. Breathable underlays reduce (but do not eliminate) the need for ventilation in cold roofs. BS 5250 still requires a minimum 25mm eaves-to-ridge ventilation path. Without it, warm moist air can still condense in the roof void in cold climates.'}
]},
building:{name:'Builder',emoji:'🧱',questions:[
{id:'b1',type:'scenario',level:1,competency:'regulation',text:'A client wants to remove a wall between kitchen and dining room. How do you determine if it\'s load-bearing?',options:['If it runs parallel to the joists it\'s definitely not load-bearing','If it has a steel — all load-bearing walls contain steels','Assess position relative to structural frame and what\'s above it — commission a structural engineer if in doubt','Non-load-bearing walls are always stud partitions'],correct:2,explanation:'No single rule reliably identifies a load-bearing wall without proper assessment. Indicators include: perpendicular to joists, on the building centreline, with structure above or below. A structural engineer\'s specification is required by Building Control for any structural alteration.'},
{id:'b2',type:'scenario',level:2,competency:'regulation',scenario:'Building a 12m² single-storey rear extension. Client has permitted development confirmation from 3 years ago.',text:'What additional regulatory step is required before starting work?',options:['Nothing — permitted development covers everything','A Building Regulations application must be submitted — planning and Building Regs are entirely separate processes','A structural engineer\'s report only','A party wall notice only'],correct:1,explanation:'Permitted Development rights address planning consent only. Building Regulations are a separate requirement under the Building Act 1984, required for any structural work, new habitable space, foundations, or drainage.'},
{id:'b3',type:'technical',level:2,competency:'technical',text:'What mortar mix should be used for general-purpose external brickwork in a moderate exposure zone?',options:['1:2 cement:sand (designation i)','1:1:6 cement:lime:sand or 1:5–6 masonry cement:sand (designation iii)','1:4 cement:sand (designation ii)','Pure cement mortar'],correct:1,explanation:'BS EN 998-2 and NHBC Standards recommend designation (iii) mortar for most domestic external brickwork. Stronger mixes (designation i or ii) are too rigid — they cause brick spalling as the joint becomes harder than the brick.'},
{id:'b4',type:'scenario',level:2,competency:'judgement',scenario:'During excavation for an extension foundation, soil becomes soft and waterlogged at 600mm. The specification was for 900mm strip foundations.',text:'What should you do?',options:['Continue to specified 900mm — the spec covers this','Stop, excavate test pits, and contact the structural engineer before proceeding','Deepen to 1200mm — standard practice in soft ground','Install a raft foundation without consulting a structural engineer'],correct:1,explanation:'Unexpected ground conditions require stopping and reassessing. Soft waterlogged ground means the specified foundation may not achieve adequate bearing. The structural engineer must be informed immediately. Document everything in writing.'},
{id:'b5',type:'regulation',level:1,competency:'regulation',text:'Part A of the Building Regulations covers:',options:['Accessible and adaptable dwellings','Structure','Conservation of fuel and power','Resistance to the passage of sound'],correct:1,explanation:'Building Regulations Approved Documents: Part A = Structure, Part B = Fire Safety, Part C = Resistance to Moisture, Part E = Sound, Part F = Ventilation, Part L = Conservation of Fuel and Power, Part M = Accessibility.'},
{id:'b6',type:'scenario',level:3,competency:'judgement',scenario:'Building a two-storey extension. The inspector notes cavity wall insulation was installed with a gap to the inner leaf, and wall ties are not angled to shed water outward.',text:'What is the consequence and correct action?',options:['Minor points — continue and rectify on final inspection','Both are potentially serious — inward-sloping ties channel water to the inner leaf causing damp; inspector may issue a stop notice','Cavity insulation gaps reduce performance but are not a Building Regs failure','These are non-structural and don\'t affect compliance'],correct:1,explanation:'Inward-sloping wall ties direct water and mortar droppings onto insulation and inner leaf, causing persistent damp penetration. Both constitute non-compliance with Part C and Part L. A building inspector can issue a stop notice or require written corrective action before proceeding.'},
{id:'b7',type:'truefalse',level:1,competency:'regulation',text:'TRUE or FALSE: A CDM Principal Designer must be appointed for all domestic extension projects in England.',correct:false,explanation:'FALSE. Under CDM 2015, a Principal Designer is required where there are two or more contractors working simultaneously. For a single-contractor domestic extension, the duties are more limited. The domestic client passes their CDM duties to the contractor.'},
{id:'b8',type:'technical',level:3,competency:'technical',text:'Installing a steel beam spanning 3.8m. Structural engineer specifies 150mm minimum bearing. The existing wall is 215mm brick. What must be checked?',options:['150mm bearing is standard and needs no further checks','Padstones must be specified to spread the concentrated beam end load over the masonry below','Use 100mm bearing — 150mm is excessive for domestic loads','Steel beams do not require padstones in domestic construction'],correct:1,explanation:'150mm bearing on a 215mm wall leaves only 65mm of masonry beyond the beam end. Padstones (precast concrete or engineering brick, min 215×215mm) are required to spread the concentrated point load. Without padstones, masonry may crush below the beam end.'},
{id:'b9',type:'select-all',level:2,competency:'regulation',text:'Which of the following triggers a requirement to serve a Party Wall etc. Act 1996 notice? Select ALL that apply.',options:['Building a new wall on or at the boundary line','Cutting into or underpinning a party wall','Any extension within 6 metres of a neighbour\'s property','Excavating within 3–6 metres of a neighbouring structure to a depth below the neighbour\'s foundations','Any new build in a conservation area'],correct:[0,1,3],explanation:'Party Wall etc. Act 1996 applies to: work on/to party walls (Section 2), new walls on the boundary (Section 1), and excavations within 3–6m of a neighbouring building where foundations are deeper (Section 6). Extensions within 6m are not automatically notifiable unless excavation depths trigger Section 6.'},
{id:'b10',type:'scenario',level:3,competency:'judgement',text:'Rendering a Victorian terrace externally for the first time. The client wants sand-cement render directly on original lime-mortar brickwork. What is your advice?',options:['Sand-cement is fine on any substrate','Apply SBR bonding agent first and cement render will be fine','Hard cement render over soft lime-mortar brickwork can cause spalling and moisture trapping — specify a lime-based or NHL render instead','Rake out all lime mortar and replace with cement before rendering'],correct:2,explanation:'Victorian brickwork uses soft lime mortar to allow moisture to breathe. Hard cement render creates an impermeable skin — moisture penetrating through cracks cannot escape, causing freeze-thaw spalling of bricks and damp penetration. Specify hydraulic lime or silicone render with similar vapour permeability to the original construction.'},
{id:'b11',type:'calculation',level:2,competency:'technical',text:'Calculate concrete volume for a strip foundation 600mm wide × 300mm deep × 28 metres long, including 10% wastage.',unit:'m³',correct:5.54,tolerance:0.3,explanation:'Volume = 0.6 × 0.3 × 28 = 5.04 m³. With 10% wastage: 5.04 × 1.1 = 5.544 ≈ 5.54 m³. Accurate volume calculation is critical for ordering ready-mix — excess is expensive, shortage risks cold joints.'},
{id:'b12',type:'truefalse',level:2,competency:'regulation',text:'TRUE or FALSE: Permitted Development in England allows a detached householder to build a rear extension up to 8 metres deep automatically without any local authority involvement.',correct:false,explanation:'FALSE. The 8m allowance for detached houses requires going through the Neighbour Consultation Scheme with the LPA first. Automatic PD without LA involvement is 4m for detached, 3m for semi/terraced. Also removed for listed buildings and conservation areas.'}
]},
decorating:{name:'Painter & Decorator',emoji:'🎨',questions:[
{id:'d1',type:'technical',level:1,competency:'technical',text:'New bare plaster needs decorating. What is the correct first coat to apply?',options:['Full-strength vinyl matt emulsion','A mist coat — emulsion diluted approximately 70:30 paint to water','Alkali-resistant primer','Zinsser BIN shellac-based primer'],correct:1,explanation:'New plaster is highly alkaline and absorbent. A mist coat (approx 70% emulsion + 30% water) seals the plaster and allows it to breathe during curing. Full-strength emulsion on new plaster can peel as trapped moisture tries to escape.'},
{id:'d2',type:'scenario',level:2,competency:'safety',scenario:'Sanding old paintwork in a pre-1978 property. Client says the house has never been stripped back to bare walls.',text:'What is your primary safety concern and required action?',options:['Old paint is not a hazard — modern paints are water-based','Pre-1978 paint may contain lead — test before sanding and use FFP3 respiratory protection with contained dust disposal','Only commercial properties used lead paint','Wear a standard dust mask and open windows'],correct:1,explanation:'Lead was used in domestic paint until the early 1970s–1980s. Sanding creates fine lead dust — a serious inhalation hazard. Under COSHH and the Control of Lead at Work Regulations 2002: test with a lead swab, use FFP3 mask, HEPA vacuum, seal off the area, and dispose of waste as hazardous material.'},
{id:'d3',type:'technical',level:1,competency:'technical',text:'Correct sequence for preparing and painting new external timber joinery:',options:['Prime → Undercoat → Topcoat','Sand → Fill → Topcoat × 2','Sand → Knotting compound on all knots → Primer → Undercoat → Topcoat × 2','Clean → Sand → Single microporous topcoat only'],correct:2,explanation:'New external timber requires: sanding (moisture raises the grain), knotting compound over resinous knots (prevents bleed-through staining), alkyd primer, undercoat, and minimum two topcoats for durability.'},
{id:'d4',type:'scenario',level:2,competency:'judgement',scenario:'Papering a feature wall with heavyweight embossed vinyl. The paste-soaked paper tears when positioned.',text:'Most likely cause?',options:['Over-soaking — reduce paste and soak time','Insufficient soaking time — apply heavier paste mix and extend soak to 8–12 minutes','Wrong paste — switch to border adhesive','Paper too thick — use lining paper instead'],correct:1,explanation:'Heavyweight embossed vinyls require 8–12 minutes soaking time to relax the paper backing. Under-soaking leaves the paper stiff and prone to tearing. Use heavy-duty wallpaper paste at the heavier mix ratio specified for vinyls, and cover the folded paper on the pasting table during soaking.'},
{id:'d5',type:'regulation',level:1,competency:'regulation',text:'You use solvent-based paints regularly at work. Under COSHH, what must you do?',options:['Nothing — over-the-counter products carry no COSHH requirements','Complete a COSHH assessment identifying the hazard, exposure route, and control measures before use','Keep the paint tin in a locked storage box','Only use them outdoors'],correct:1,explanation:'COSHH (Control of Substances Hazardous to Health Regulations 2002) requires a risk assessment for any hazardous substance used at work, including solvent-based paints. Identify hazard (VOCs), assess exposure route (inhalation), implement controls (ventilation, RPE with organic vapour cartridge, skin protection), and record the assessment.'},
{id:'d6',type:'technical',level:2,competency:'technical',text:'Painting a north-facing exterior wall with visible algae and mould. What preparation is required before applying masonry paint?',options:['Sand smooth and apply two coats of masonry paint immediately','Apply biocidal wash, allow dwell time, pressure-wash, dry fully, prime bare areas, then apply masonry paint','Scrub with wire brush and apply paint','Mould will be killed by the paint — no pre-treatment needed'],correct:1,explanation:'Painting over live algae/mould causes failure within 1–2 years as organisms grow under the film. Correct sequence: fungicidal wash (24hr dwell), pressure/scrub wash, 48+ hours drying, stabilising primer on friable areas, minimum two coats quality masonry paint.'},
{id:'d7',type:'scenario',level:3,competency:'judgement',scenario:'A client in a Georgian property wants you to paint original lime-based decorative coving that hasn\'t been painted in 30 years. Structurally sound.',text:'What is the correct approach?',options:['Any standard emulsion will work — just clean and paint','Strip all old finishes and apply oil-based primer','Clean, consolidate any friable areas with dilute acrylic consolidant, apply limewash or breathable mineral-based paint — avoid modern vinyl emulsions','Apply standard latex emulsion — more durable than lime products'],correct:2,explanation:'Original lime coving is a breathable, alkaline substrate. Vinyl emulsions trap moisture. Appropriate finishes: traditional limewash, distemper, or silicate/mineral paint. Use dilute acrylic consolidants (not PVA, which forms a sealing film) to stabilise friable surfaces. Incorrect products can permanently damage original decorative plasterwork.'},
{id:'d8',type:'truefalse',level:1,competency:'safety',text:'TRUE or FALSE: Any decorator using a spray gun in an occupied domestic property must isolate the work area and wear appropriate respiratory protection.',correct:true,explanation:'TRUE. Airborne paint particles from spray application are a significant inhalation risk. COSHH requires: seal the area from occupied spaces, occupants must leave during spraying, and the sprayer must wear at minimum FFP2 (P2) mask for water-based coatings, or supplied-air respirator for 2-pack/isocyanate products.'},
{id:'d9',type:'scenario',level:3,competency:'judgement',text:'Applying two-pack epoxy floor coating in a commercial kitchen. Substrate moisture = 5.2%. Manufacturer maximum: 4.5%. What should you do?',options:['Apply at 5.2% — 0.7% over is negligible','Apply moisture-tolerant primer first then overcoat','Wait for the substrate to dry below 4.5%, or specify a moisture-tolerant epoxy system rated for the measured RH','Ask the client\'s permission to proceed'],correct:2,explanation:'Two-pack epoxy is extremely moisture-sensitive. Application above specification limits causes poor adhesion, bubbling, and delamination. Wait for adequate drying (dehumidification may help), or specify a moisture-tolerant system. Proceeding regardless constitutes a breach of manufacturer specification and creates liability for failure.'},
{id:'d10',type:'scenario',level:2,competency:'practice',text:'A client reports "picture framing" — perimeter of each wall appears a slightly different shade to the centre. What caused this?',options:['Wrong paint — tins from different batches','Cutting-in brush marks drying before the roller fills the centre, creating visible lap marks','The wall surface was not properly prepared','The paint was too thick'],correct:1,explanation:'"Picture framing" occurs when brush-applied edges dry before the roller meets them. When the roller overlaps dry brush lines it creates a subtle texture/sheen difference. Prevention: maintain a wet edge — cut in small sections and immediately roll to meet them before drying.'},
{id:'d11',type:'calculation',level:2,competency:'technical',text:'Bedroom to paint: 4m × 4.5m floor, 2.4m ceiling. One door (1.0×2.0m) and two windows (each 1.2×1.1m). Coverage rate 12m²/litre. How many 5-litre tins for TWO coats?',unit:'tins',correct:3,tolerance:0,explanation:'Wall area: perimeter = (4+4.5)×2 = 17m. Area = 17 × 2.4 = 40.8m². Deduct door = 2m², windows = 2.64m². Net = 36.16m². Two coats = 72.32m². At 12m²/L = 6.03 litres minimum. Professional practice: order 3 tins (15L) to allow for roller nap absorption, cutting-in waste, and touch-ups.'},
{id:'d12',type:'scenario',level:3,competency:'judgement',text:'Client wants to repaint a radiator with standard vinyl emulsion to match the walls exactly. The radiator has flaking previous paint. What do you advise?',options:['Apply vinyl emulsion — it will match perfectly and is fine for radiators','Strip the radiator, apply metal primer, and use radiator enamel or alkyd satinwood','Homeowner can do this themselves — just clean and apply emulsion','Apply PVA first then emulsion'],correct:1,explanation:'Vinyl emulsion is not heat-resistant and will soften, yellow, and crack on a heated radiator. Correct approach: strip flaking paint, treat rust, apply metal primer, then use radiator enamel or alkyd satinwood which withstands heat. Advise the client the slight gloss will not exactly match the walls.'}
]},
flooring:{name:'Flooring Specialist',emoji:'🔲',questions:[
{id:'fl1',type:'technical',level:1,competency:'technical',text:'Before laying solid hardwood flooring over a concrete subfloor, what is the critical preparation check?',options:['Confirm concrete is at least C20 strength','Measure moisture content — must be below 3% (RH below 75%) using a hygrometer hood test','Check the surface is perfectly level','Apply two coats of PVA to seal the concrete'],correct:1,explanation:'Solid hardwood is extremely moisture-sensitive. Concrete subfloors must be tested for moisture content. The threshold for most solid wood flooring is below 3% or RH below 75% (BS 8201). If moisture is too high, apply a DPM (liquid-applied or sheet) before installation.'},
{id:'fl2',type:'scenario',level:2,competency:'judgement',scenario:'Laying 220mm-wide engineered oak flooring over underfloor heating. UFH max water temperature 45°C, max floor surface 27°C.',text:'What additional step is required before installation?',options:['No additional steps — just lay and connect UFH after','Acclimatise the boards in the room with UFH at operating temperature for 72–96 hours minimum','Apply a moisture barrier regardless of moisture readings','Solid wood must never be used over UFH — specify LVT instead'],correct:1,explanation:'Wide engineered boards expand and contract significantly with temperature and humidity. Before installing over UFH, boards must acclimatise at operating temperature for minimum 72–96 hours per manufacturer specification, conditioning them to the steady-state environment they will experience in service.'},
{id:'fl3',type:'regulation',level:1,competency:'regulation',text:'Building Regulations Part M specifies the maximum threshold height for a door in an accessible/adaptable dwelling (M4(2)):',options:['15mm','25mm','40mm','No maximum specified'],correct:0,explanation:'Approved Document M (M4(2)) requires door thresholds no more than 15mm high, chamfered or ramped. Even in standard M4(1) dwellings, thresholds above 25mm constitute a trip hazard. Flooring installers must detail transitions accordingly and use appropriate reducer strips.'},
{id:'fl4',type:'scenario',level:2,competency:'technical',scenario:'Tiling a bathroom floor with 600×600mm porcelain tiles. Subfloor is 18mm T&G chipboard over timber joists with approximately 4mm deflection over 1.2m span.',text:'Can you proceed with direct tile installation?',options:['Yes — 18mm chipboard is adequate for 600mm format tiles','No — chipboard is unsuitable for tiling; overlay with 12mm external-grade plywood or use a decoupling membrane system','Yes — use flexible adhesive only to compensate','Only if grout joints are over 5mm wide'],correct:1,explanation:'Chipboard is unsuitable for tiling: hygroscopic expansion with moisture; insufficient rigidity (4mm deflection over 1.2m far exceeds industry standard L/360). Large-format porcelain is especially vulnerable to subfloor movement. Solution: 12mm external-grade plywood (screwed, staggered joints) or a decoupling membrane (Schlüter Ditra, etc.).'},
{id:'fl5',type:'technical',level:2,competency:'technical',text:'For large-format porcelain tiles (>600mm) on a heated screed, which adhesive classification per EN 12004 is required?',options:['C1 (normal-setting cement adhesive)','C2S2 (improved cement adhesive with deformability class S2)','D2 (dispersion adhesive)','R2 (reaction resin adhesive)'],correct:1,explanation:'C2 (improved adhesive, higher bond strength) + S2 (deformability class allowing movement) is required. C2 ensures adequate bond for heavy large-format porcelain. S2 deformability allows the adhesive bed to absorb thermal expansion/contraction from UFH without transmitting stress to tiles, preventing delamination or cracking.'},
{id:'fl6',type:'scenario',level:3,competency:'judgement',scenario:'After completing an 80m² LVT floating click installation, the client reports several planks tenting (lifting in the middle) 3 weeks later.',text:'Most likely cause and remedial action?',options:['LVT is defective — claim under warranty','Room temperature exceeded maximum — ventilate and it will settle','Insufficient or missing perimeter expansion gaps — LVT is expanding with nowhere to go, causing buckling','Incorrect cleaning products caused the planks to warp'],correct:2,explanation:'LVT floating systems expand significantly with temperature. For an 80m² room (~9m long), a 5°C increase produces ~3.6mm expansion. Without adequate perimeter gaps (minimum 5mm, recommended 8–10mm), the floor buckles upward. Remedy: cut back expansion gaps. This is the most common LVT defect and is entirely installer error.'},
{id:'fl7',type:'truefalse',level:2,competency:'technical',text:'TRUE or FALSE: Carpet gripper rods should be positioned at a distance from the wall approximately equal to 2/3 of the carpet pile thickness.',correct:true,explanation:'TRUE. Gripper rods are positioned so that when carpet is stretched and hooked over the pins, the edge falls neatly into the gap between gripper and wall. Approximately 2/3 of pile depth is the industry standard. Too far: carpet pulls off. Too close: carpet bunches at the skirting.'},
{id:'fl8',type:'scenario',level:3,competency:'judgement',scenario:'Installing natural stone travertine tiles (400×400mm). Tiles show significant thickness variation across the batch — 8mm to 12mm.',text:'What is the correct approach?',options:['Return the tiles — natural stone must be uniform thickness','Apply a thick unregulated bed and float tiles level','Back-butter every tile fully and set to level using a tile levelling clip-and-wedge system, with notched trowel adhesive on the substrate','Grind down the thicker tiles to achieve uniformity'],correct:2,explanation:'Thickness variation in natural stone is common and managed by: back-buttering every tile (ensuring 100% adhesive coverage — essential for natural stone), notched trowel on the substrate, and a tile levelling system (clips and wedges) to achieve a flat finish.'},
{id:'fl9',type:'technical',level:3,competency:'technical',text:'Minimum recommended acclimatisation period for solid hardwood flooring in a living environment before installation:',options:['24 hours','3–5 days','7–14 days','No acclimatisation needed if moisture tested'],correct:2,explanation:'Solid hardwood requires 7–14 days of acclimatisation in the installation environment to stabilise to ambient temperature and humidity. Even with moisture testing, the boards must reach equilibrium moisture content (EMC) for the specific location. Rushing this step results in gap formation or buckling after installation.'},
{id:'fl10',type:'scenario',level:2,competency:'practice',text:'After installing an engineered wood floor glued to concrete, the client complains of squeaking when walking. What is the most likely cause?',options:['The adhesive has failed — the floor needs relaying','Squeaking is caused by boards not fully bedding into adhesive (hollow spots) — re-pressing or spot adhesive injection may resolve isolated areas','The underfloor heating is incompatible','The floor was installed too early and needs 6 months to settle'],correct:1,explanation:'Squeaking in glued-down floors is almost always hollow spots where boards are not fully bonded. This occurs from: insufficient adhesive coverage, wrong trowel notch size, adhesive skin-over before laying, or boards not pressed firmly enough. Isolated squeaks can be resolved by injecting adhesive through small drill holes.'},
{id:'fl11',type:'select-all',level:2,competency:'technical',text:'When laying porcelain floor tiles in a commercial kitchen, which are mandatory requirements? Select ALL that apply.',options:['Slip resistance rating R10 or above for wet areas','Full adhesive coverage (minimum 95% for vitrified tiles in commercial use)','Exactly 3mm grout joints for 300mm+ format tiles','Movement joints at perimeter and at maximum 5–8m intervals in field','Flexible waterproof grout in all joints'],correct:[0,1,3],explanation:'Commercial kitchen requirements: R10+ slip resistance, 95% adhesive coverage for vitrified tiles (EN 1308 / BS 5385 Part 2), movement joints at perimeter and at 5–8m internal intervals. Grout joint width depends on tile format and manufacturer — not a fixed 3mm rule. Standard cementitious grout is acceptable; flexible grout is beneficial but not universally mandatory.'},
{id:'fl12',type:'calculation',level:2,competency:'technical',text:'Laying 600×600mm porcelain tiles in a 5.4m × 7.2m room with 5% wastage. How many tiles do you need to order?',unit:'tiles',correct:120,tolerance:3,explanation:'Room area = 5.4 × 7.2 = 38.88 m². Tile area = 0.36 m². Base tiles = 38.88 ÷ 0.36 = 108 tiles. With 5% wastage: 108 × 1.05 = 113.4 → round to 114. With perimeter cutting (additional 5–7% typical) professional practice is to order 120 tiles. Always round up — partial boxes are often non-returnable.'}
]},
architecture:{name:'Architect',emoji:'📐',questions:[
{id:'a1',type:'regulation',level:1,competency:'regulation',text:'The Architects Registration Board (ARB) is established under which legislation?',options:['The Town and Country Planning Act 1990','The Architects Act 1997','The Building Act 1984','The Professional Qualifications Act 2022'],correct:1,explanation:'The ARB is established under the Architects Act 1997. The Act protects the title "architect" in the UK — it is a criminal offence for a person not registered with ARB to use this title.'},
{id:'a2',type:'scenario',level:2,competency:'regulation',scenario:'Your client wants to extend a Grade II listed semi-detached house with a two-storey rear extension and replace the original sash windows with uPVC double glazing.',text:'What consents are required?',options:['Planning permission only — listing covers structural changes but not cosmetic ones','Listed Building Consent is required for both the extension and the window replacement; planning permission is also needed for the extension','Building Regulations approval only — listed buildings are exempt from planning','No consents required if the work is reversible'],correct:1,explanation:'Any works affecting the special architectural or historic interest of a listed building require Listed Building Consent — including extensions AND alterations to original fabric like windows. The uPVC window replacement is almost certain to be refused. Planning permission is also required for the extension.'},
{id:'a3',type:'technical',level:2,competency:'technical',text:'A client wants to remove two load-bearing walls and replace them with a single steel beam spanning 7.2 metres. What must the architect produce before construction?',options:['A planning application and nothing else','Structural engineer\'s calculations, a Building Regulations full plans application, and construction-phase drawings including beam specification and padstone details','A Design and Access Statement and party wall notice only','A Building Notice is sufficient — no drawings required for internal alterations'],correct:1,explanation:'Removing load-bearing walls and installing a 7.2m steel beam is a notifiable structural alteration under Part A. Required: structural engineer\'s calculations, Full Plans Building Regulations submission (or detailed working drawings), and padstone specification.'},
{id:'a4',type:'scenario',level:3,competency:'judgement',scenario:'You are Principal Designer on a residential refurbishment. Mid-project, the main contractor proposes changing specified cavity wall insulation from rigid PIR board to mineral wool to reduce cost, arguing equivalence.',text:'What is your responsibility under CDM 2015?',options:['The contractor\'s choice — cost decisions are not the Principal Designer\'s concern','Approve informally — mineral wool is a standard product','Assess the design change for CDM compliance, update the Construction Phase Plan and H&S File if necessary, and do not approve changes that introduce new risks without formal review','Refuse all variations as a matter of principle'],correct:2,explanation:'Under CDM 2015, the Principal Designer must ensure the design eliminates or reduces foreseeable risks. A material change affects: thermal performance (may need wider cavity for Part L compliance), condensation risk (different vapour permeability), and installation method. The PD must formally review, may need to update the H&S File, and must not approve changes affecting design intent without proper assessment.'},
{id:'a5',type:'regulation',level:1,competency:'regulation',text:'Under the ARB Architects Code, which of the following is NOT a required standard of professional conduct?',options:['Act with honesty and integrity','Manage your business competently','Guarantee a fixed price for all services before commencing work','Maintain adequate and appropriate insurance'],correct:2,explanation:'The ARB Architects Code requires: honesty and integrity, competent business management, clear fee arrangements, and adequate PI insurance. It does NOT require a fixed price guarantee — fees may be on a time charge, percentage, or lump sum basis depending on agreement with the client.'},
{id:'a6',type:'scenario',level:2,competency:'judgement',scenario:'A client wants to design a new house on agricultural Green Belt land. They say neighbouring extensions set a precedent.',text:'What advice do you give?',options:['Proceed with a full planning application — precedent is established','Green Belt policy strongly resists new residential development. Extensions to existing buildings set no precedent for new dwellings on agricultural land','Design a barn conversion instead — always permitted in the Green Belt','Apply for Class Q permitted development — all agricultural buildings can convert to residential without planning permission'],correct:1,explanation:'NPPF Chapter 13 strongly restricts new residential development in the Green Belt. "Very special circumstances" must be demonstrated — an extremely high bar. Neighbouring extensions to existing dwellings create no precedent for new dwellings on greenfield land. Class Q PD has significant prior-use and condition requirements and does not apply to bare land.'},
{id:'a7',type:'technical',level:2,competency:'technical',text:'Maximum permitted rise for each step on a private staircase in a new dwelling (Approved Document K):',options:['180mm','200mm','220mm','250mm'],correct:2,explanation:'Approved Document K specifies for private stairs (dwellings): maximum rise 220mm, minimum going 220mm. The relationship between rise and going should satisfy: 2R + G = 550–700mm. For common stairs in blocks of flats, different rules apply (max 190mm rise).'},
{id:'a8',type:'select-all',level:2,competency:'technical',text:'Under Building Regulations Part L1A (new residential, England), which of the following demonstrate compliance? Select ALL that apply.',options:['SAP (Standard Assessment Procedure) calculation','Air tightness testing at practical completion','U-value calculations for each building element','A written maintenance plan for the heating system','Photovoltaic panels installed on the roof'],correct:[0,1,2],explanation:'Part L compliance for new dwellings requires: a SAP energy calculation, air tightness testing at completion (typically ≤5 m³/(h.m²) at 50Pa), and U-value calculations for all fabric elements. A maintenance plan and PV panels are not required compliance submission elements, though PV may contribute to the SAP rating.'},
{id:'a9',type:'scenario',level:3,competency:'judgement',scenario:'Preparing planning drawings for a 40-apartment residential development. Pre-application consultation was positive. You discover the site is in Flood Zone 2.',text:'What is required before the planning application can proceed?',options:['Submit the application — pre-application support means it will be approved regardless of flood risk','A site-specific Flood Risk Assessment must be prepared and submitted with the planning application','No action required — Flood Zone 2 is low risk and residential development is always acceptable','Raise ground floor level by 300mm and no FRA is required'],correct:1,explanation:'NPPF Chapter 14 requires a site-specific FRA for all development in Flood Zones 2 and 3. The FRA must assess the risk, demonstrate the development is safe for its lifetime (100 years + climate change allowance), and apply the Sequential/Exception Test if necessary. Pre-application support does not waive this requirement.'},
{id:'a10',type:'technical',level:3,competency:'technical',text:'Current Building Regulations Part L1A (England, 2021) specifies a target U-value for external walls of new dwellings as approximately:',options:['0.18 W/m²K','0.28 W/m²K','0.35 W/m²K','0.45 W/m²K'],correct:1,explanation:'Part L1A (2021) specifies a target U-value of 0.28 W/m²K for external walls of new dwellings as the "notional building" standard. The actual required U-value is determined through the SAP calculation and may vary. Roofs: 0.13. Ground floors: 0.17. Windows: 1.4 W/m²K.'},
{id:'a11',type:'truefalse',level:2,competency:'regulation',text:'TRUE or FALSE: An architect who is a sole trader must hold Professional Indemnity (PI) insurance as a mandatory requirement under the ARB Architects Code.',correct:true,explanation:'TRUE. The ARB Architects Code (Standard 8) requires all registered architects to have adequate and appropriate professional indemnity insurance, whether employed or in sole practice. The code does not specify a minimum level but it must be appropriate to the scale and nature of work undertaken.'},
{id:'a12',type:'scenario',level:3,competency:'judgement',scenario:'You are asked to certify a completed new-build house complies with Building Regulations. However, you have concerns that wall ties in the cavity wall construction may not have been correctly installed and you cannot confirm compliance without opening up the works.',text:'What is the appropriate action?',options:['Issue the completion certificate — you cannot be held responsible for hidden works','Refuse to certify until appropriate investigation confirms the wall tie installation','Certify the visible works only and note your caveat in writing','Ask the builder to provide a letter confirming compliance — this transfers responsibility'],correct:1,explanation:'Certifying Building Regulations compliance requires that the architect can stand behind the certification. Where there is reasonable doubt about hidden works, the architect should not certify until appropriate investigation is completed or building inspector inspection records confirm compliance. Certifying works you have doubt about exposes the practice to professional negligence claims and ARB regulatory action.'},
{id:'a13',type:'calculation',level:2,competency:'technical',text:'A south-facing glazed wall has 12m² of double glazing (U-value 1.4 W/m²K). Inside temperature 20°C, outside -2°C. Approximate heat loss through the glazing alone?',unit:'Watts',correct:369.6,tolerance:15,explanation:'Heat loss (W) = U-value × Area × ΔT = 1.4 × 12 × (20−(−2)) = 1.4 × 12 × 22 = 369.6 W. Triple glazing (U=0.8) would reduce this to 211W, saving 158W continuously during cold periods.'}
]},
generic:{name:'General Trade',emoji:'🛠️',questions:[
{id:'gt1',type:'regulation',level:1,competency:'regulation',text:'The Health and Safety at Work etc. Act 1974 places a general duty on employers to, so far as is reasonably practicable:',options:['Ensure no accidents ever occur on a worksite','Provide and maintain safe plant, systems of work, and workplace, and to provide adequate training and supervision','Complete a risk assessment for every single task','Wear PPE at all times on site'],correct:1,explanation:'Section 2 of the HSWA 1974 places a general duty on employers to ensure, so far as is reasonably practicable, the health, safety and welfare of all employees. Key duties include: safe plant, safe systems of work, safe premises, adequate information/instruction/training, and a safe working environment.'},
{id:'gt2',type:'scenario',level:1,competency:'safety',text:'Who is legally required to document a risk assessment for a business with 5 or more employees?',options:['The employee who will carry out the work','The employer — significant findings must be recorded in writing','The client or homeowner','The Health and Safety Executive'],correct:1,explanation:'The Management of Health and Safety at Work Regulations 1999 (Regulation 3) require employers to carry out risk assessments. Employers with 5 or more employees must record the significant findings in writing.'},
{id:'gt3',type:'technical',level:1,competency:'technical',text:'COSHH stands for Control of Substances Hazardous to Health. What does the legislation require you to do?',options:['Carry a valid CSCS card at all times','Assess risks from hazardous substances and implement adequate control measures before use','Never use hazardous substances without an employer present','Follow the manufacturer\'s data sheet without any further assessment required'],correct:1,explanation:'COSHH Regulations 2002 require: identifying hazardous substances, assessing the risk to health, deciding what control measures are needed (eliminate, substitute, engineering controls, PPE), implementing controls, and monitoring effectiveness. Applies to paints, adhesives, solvents, dust, asbestos, and many other site substances.'},
{id:'gt4',type:'scenario',level:2,competency:'judgement',scenario:'A client verbally agrees to additional work costing £2,000 beyond your original contract. You complete the work. The client then refuses to pay, claiming they never agreed.',text:'What is the lesson and what should you do in future?',options:['Verbal agreements are legally binding — take the client to court immediately','Always agree and confirm variations in writing before carrying out additional work — verbal agreements are difficult to enforce','Add a clause that all variations are automatically agreed when you start work','This is common — accept the loss to protect the client relationship'],correct:1,explanation:'Verbal contracts can be legally binding but are extremely difficult to enforce without written evidence. Best practice: agree all variations in writing (even a WhatsApp message confirmed by both parties) before commencing additional work. Include: scope, agreed cost, and the client\'s confirmation.'},
{id:'gt5',type:'regulation',level:1,competency:'regulation',text:'The Construction Industry Scheme (CIS) requires a contractor to deduct tax at source when:',options:['Employing a full-time employee','Paying a subcontractor for construction work','Any tradesperson invoices a homeowner','A business is VAT registered'],correct:1,explanation:'CIS requires contractors to deduct tax when paying subcontractors for construction work. The standard rate is 20% for registered subcontractors, 30% for unregistered. Gross payment status (0% deduction) requires HMRC approval. Homeowners are NOT contractors under CIS — it applies to business-to-business construction work only.'},
{id:'gt6',type:'scenario',level:2,competency:'safety',scenario:'You are working on a ladder to fit guttering. A colleague notices the feet are on uneven ground and the angle appears too steep — almost vertical.',text:'What is the correct ladder angle and what should you do?',options:['The angle looks fine — steeper is safer','The correct angle is 75° to horizontal (1 out for every 4 up). Stop work and reposition before continuing','Ladders have no required angle — just ensure the feet are secure','Attach a fall arrest harness and continue'],correct:1,explanation:'HSE guidance and BS EN 131 specify a ladder angle of 75° (the 1 in 4 rule: base 1 unit out for every 4 units of height). Too steep: increased risk of backward fall. Too shallow: risk of feet slipping. Stop, reposition, and level the ground if necessary.'},
{id:'gt7',type:'truefalse',level:1,competency:'regulation',text:'TRUE or FALSE: If you are self-employed with no employees, you do not need to hold any public liability insurance to work on domestic properties.',correct:false,explanation:'FALSE. While public liability insurance is not legally mandatory for the self-employed in most cases, most domestic clients and all commercial clients require it. Without PLI, you are personally liable for any injury or property damage caused to third parties. Most trade platforms require minimum £2M PLI as a condition of listing.'},
{id:'gt8',type:'scenario',level:2,competency:'practice',text:'A client asks you to start work without a written contract "to keep things simple." The job is worth £8,500. What should you do?',options:['Agree — a handshake is fine for jobs under £10,000','Politely insist on a written contract before starting — this protects both you and the client','Send an invoice after completion — that counts as a contract','Ask for a 50% deposit but no contract is needed'],correct:1,explanation:'A written contract is essential for any job regardless of size. It should include: scope of work, materials specification, price, payment schedule, start and end dates, and variation procedure. Without a contract, disputes over scope, extras, and payment terms are almost impossible to resolve fairly.'},
{id:'gt9',type:'technical',level:2,competency:'technical',text:'The CIS deduction rate for a subcontractor who is CIS registered but does NOT hold gross payment status is:',options:['0% — CIS registered means no deduction','20%','30%','40%'],correct:1,explanation:'CIS registered subcontractors (standard status) have 20% deducted at source by the contractor. Subcontractors not registered with HMRC suffer a 30% deduction. Gross payment status (0% deduction) is available to subcontractors with a turnover above a threshold and a good tax compliance history.'},
{id:'gt10',type:'scenario',level:3,competency:'judgement',scenario:'You discover asbestos-containing material (ACM) in a domestic property during a kitchen strip-out. The ACM appears intact — an artex coating on the ceiling. Your client wants you to continue immediately.',text:'What is the correct action?',options:['Continue — intact asbestos in good condition is safe to work around without protection','Stop work, notify the client in writing, and commission a licensed asbestos surveyor to assess and manage the material before any further work','Remove it yourself — decorating contractors can always remove ACM in domestic properties','Cover it with plasterboard and continue — this is an acceptable management solution'],correct:1,explanation:'The Control of Asbestos Regulations 2012 require that before any work that could disturb ACM, the material must be properly identified and managed. Artex may contain chrysotile (white asbestos) in properties built or renovated before 2000. Disturbing or removing ACM without proper procedures risks serious health consequences and criminal liability.'},
{id:'gt11',type:'regulation',level:1,competency:'regulation',text:'Under GDPR/UK data protection law, if you store client names, addresses, and phone numbers on your business phone or computer, you must:',options:['Register with the ICO and pay a data protection fee (unless exempt)','Delete all client data within 6 months','Never store client data digitally','Share client data with HMRC on request automatically'],correct:0,explanation:'Most sole traders and small businesses holding client personal data must register with the ICO and pay a nominal annual fee (typically £40–60). Some exemptions apply. Failing to register is a civil offence. Data must be kept securely, not held longer than necessary, and clients can request access.'},
{id:'gt12',type:'truefalse',level:2,competency:'practice',text:'TRUE or FALSE: Under the Consumer Rights Act 2015, if a tradesperson carries out domestic work that is not of satisfactory quality, the homeowner can ask for a free repair within 6 months without having to prove the fault existed at the time of the service.',correct:true,explanation:'TRUE. The Consumer Rights Act 2015 applies to business-to-consumer service contracts. If work is not of satisfactory quality, the client is entitled to ask for repeat performance (free repair) as the first remedy. Within the first 6 months, the burden of proof lies with the trader, not the consumer.'}
]}
};

